mapper.select:
    	/* com.erns.coching.member.mapper.MemberDAO.getMembList */

    	SELECT * FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
				SELECT

				FROM T_MEMB_INF AA



				ORDER BY AA.MEMB_ID
			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

    	/* com.erns.coching.member.mapper.MemberDAO.loadMemb */

 		SELECT

		FROM T_MEMB_INF AA
		WHERE 1=1

	    		AND AA.MEMB_SEQ = #{membSeq, jdbcType=INTEGER}



	    		AND AA.PTN_SEQ = #{ptnSeq, jdbcType=INTEGER}



	    		AND UPPER(AA.EMAIL) LIKE UPPER('%' || #{email, jdbcType=VARCHAR} || '%')

   		/* com.erns.coching.member.mapper.MemberDAO.load */

			SELECT

		FROM T_MEMB_INF AA

			AND AA.MEMB_SEQ = #{membSeq, jdbcType=INTEGER}

mapper.insert:
    	/* com.erns.coching.member.mapper.MemberDAO.insertMemb */


			 SELECT
			 nextval('seq_t_memb_inf') AS memb_seq,
			 gen_salt('md5') AS SALT;


		 INSERT INTO T_MEMB_INF (
			 MEMB_SEQ
			 , MEMB_ID
			 , MEMB_TYPE
			 , PTN_SEQ
			 , SALT
			 , PSWD
			 , MEMB_NAME
			 , NICKNAME
			 , PHONE
			 , EMAIL
			 , EMAIL_YN
			 , MESSAGE_YN
			 , JOIN_DTTM
			 , USE_YN
			 , WTDR_YN
			 , WTDR_DTTM
			 , DORMANT_YN
			 , PSWD_CHNG_DTTM
			 , PSWD_ERR_CNT
			 , PSWD_INIT_YN
			 , PSWD_EXP_DTTM
			 , RCT_ACS_DTTM
			 , RCT_ACS_IP
			 , RGTR
			 , RGT_DTTM
			 , CHNR
			 , CHNG_DTTM
		 ) VALUES (
			 #{membSeq, jdbcType=INTEGER}
			 , #{membId, jdbcType=VARCHAR}
			 , #{membType, jdbcType=VARCHAR}
			 , #{ptnSeq, jdbcType=INTEGER}
			 , #{salt, jdbcType=VARCHAR}
			 , ENCODE(DIGEST(#{pswd, jdbcType=VARCHAR} || #{salt,jdbcType=VARCHAR}, 'sha512'), 'hex')
			 , #{membName, jdbcType=VARCHAR}
			 , #{nickname, jdbcType=VARCHAR}
			 , #{phone, jdbcType=VARCHAR}
			 , #{email, jdbcType=VARCHAR}
			 , COALESCE(#{emailYn, jdbcType=CHAR}, 'N')
			 , COALESCE(#{messageYn, jdbcType=CHAR}, 'N')
			 , now()
			 , COALESCE(#{useYn, jdbcType=CHAR}, 'Y')
			 , COALESCE(#{wtdrYn, jdbcType=CHAR}, 'N')
			 , #{wtdrDttm, jdbcType=TIMESTAMP}
			 , COALESCE(#{dormantYn, jdbcType=CHAR}, 'N')
			 , now()
			 , 0
			 , COALESCE(#{pswdInitYn, jdbcType=CHAR}, 'N')
			 , #{pswdExpDttm, jdbcType=TIMESTAMP}
			 , #{rctAcsDttm, jdbcType=TIMESTAMP}
			 , #{rctAcsIp, jdbcType=VARCHAR}
			 , #{rgtr, jdbcType=INTEGER}
			 , now()
			 , #{chnr, jdbcType=INTEGER}
			 , now()
		 )

mapper.update:
/* com.erns.coching.popup.mapper.PopupDAO.update */

UPDATE T_MEMB_INF SET
	  MEMB_NAME = #{membName	, jdbcType=VARCHAR}
	, PHONE = #{phone			, jdbcType=VARCHAR}
	, EMAIL = #{email			, jdbcType=VARCHAR}
	, NICKNAME = #{nickname		, jdbcType=VARCHAR}
	, USE_YN = #{useYn			, jdbcType=VARCHAR}
	, CHNR = #{chnr				, jdbcType=INTEGER}
	, CHNG_DTTM = now()

	AND MEMB_SEQ 		= #{membSeq			, jdbcType=INTEGER}

